import { TabWidget } from "std-widgets.slint";
import { OverviewTab, OverviewUiRow } from "overview_tab.slint";
import { F4seTab, F4seUiRow } from "f4se_tab.slint";
import { ScannerTab, ScannerResultUiRow, ScannerFileListUiRow } from "scanner_tab.slint";
import { DowngraderWindow, DowngraderStatusUiRow, DowngraderPlanUiRow, DowngraderLogUiRow } from "downgrader_window.slint";
import { ToolsTab } from "tools_tab.slint";
import { SettingsTab } from "settings_tab.slint";
import { AboutTab } from "about_tab.slint";

export component MainWindow inherits Window {
    in-out property <string> update-source: "nexus";
    in-out property <string> log-level: "info";
    in-out property <string> overview-refresh-message: "Overview has not been refreshed.";
    in-out property <bool> overview-refresh-busy: false;
    in-out property <[OverviewUiRow]> overview-top-rows;
    in-out property <[OverviewUiRow]> overview-binary-rows;
    in-out property <[OverviewUiRow]> overview-archive-rows;
    in-out property <[OverviewUiRow]> overview-module-rows;
    in-out property <string> overview-problems-summary: "Problems: 0";
    in-out property <[OverviewUiRow]> overview-problem-rows;
    in-out property <string> overview-update-heading: "";
    in-out property <string> overview-nexus-update-label: "Nexus Mods";
    in-out property <bool> overview-nexus-update-enabled: false;
    in-out property <string> overview-github-update-label: "GitHub";
    in-out property <bool> overview-github-update-enabled: false;
    in-out property <bool> overview-game-path-enabled: false;
    in-out property <string> overview-downgrade-label: "Downgrade Manager...";
    in-out property <bool> overview-downgrade-enabled: false;
    in-out property <string> overview-downgrade-status: "Deferred until the Downgrade Manager workflow is ported.";
    in-out property <string> overview-archive-patcher-label: "Archive Patcher...";
    in-out property <bool> overview-archive-patcher-enabled: false;
    in-out property <string> overview-archive-patcher-status: "Deferred until the Archive Patcher workflow is ported.";
    in-out property <string> overview-last-action-error: "";
    in-out property <string> f4se-status-text: "F4SE scan has not run yet.";
    in-out property <bool> f4se-busy: false;
    in-out property <string> f4se-loading-or-error-text: "";
    in-out property <string> f4se-unknown-game-detail: "";
    in-out property <[F4seUiRow]> f4se-rows;
    in-out property <bool> scanner-overview-issues-enabled: true;
    in-out property <bool> scanner-errors-enabled: true;
    in-out property <bool> scanner-wrong-file-formats-enabled: true;
    in-out property <bool> scanner-loose-previs-enabled: true;
    in-out property <bool> scanner-junk-files-enabled: true;
    in-out property <bool> scanner-problem-overrides-enabled: true;
    in-out property <bool> scanner-race-subgraphs-enabled: true;
    in-out property <bool> scanner-settings-read-only: true;
    in-out property <string> scanner-scan-button-text: "Scan Game";
    in-out property <bool> scanner-scan-button-enabled: true;
    in-out property <bool> scanner-busy: false;
    in-out property <string> scanner-status-text: "";
    in-out property <string> scanner-progress-text: "";
    in-out property <float> scanner-progress-percent: 0;
    in-out property <string> scanner-result-count-text: "0 Results ~ Select an item for details";
    in-out property <[ScannerResultUiRow]> scanner-result-rows;
    in-out property <bool> scanner-show-mod-column: false;
    in-out property <bool> scanner-detail-visible: false;
    in-out property <string> scanner-detail-mod: "";
    in-out property <string> scanner-detail-problem: "";
    in-out property <string> scanner-detail-summary: "";
    in-out property <string> scanner-detail-solution: "";
    in-out property <string> scanner-action-feedback: "";
    in-out property <bool> scanner-open-path-enabled: false;
    in-out property <bool> scanner-open-url-enabled: false;
    in-out property <bool> scanner-copy-url-enabled: false;
    in-out property <bool> scanner-file-list-enabled: false;
    in-out property <bool> scanner-file-list-visible: false;
    in-out property <string> scanner-file-list-title: "Files";
    in-out property <string> scanner-file-list-description: "";
    in-out property <string> scanner-file-list-first-column: "Value";
    in-out property <string> scanner-file-list-second-column: "File";
    in-out property <[ScannerFileListUiRow]> scanner-file-list-rows;
    in-out property <bool> scanner-auto-fix-button-visible: false;
    in-out property <string> scanner-auto-fix-button-label: "Auto-Fix";
    in-out property <bool> scanner-auto-fix-button-enabled: false;
    in-out property <string> scanner-auto-fix-status-text: "";
    in-out property <bool> scanner-auto-fix-results-visible: false;
    in-out property <string> scanner-auto-fix-results-title: "Auto-Fix Results";
    in-out property <string> scanner-auto-fix-results-summary: "";
    in-out property <string> scanner-auto-fix-results-details: "";
    property <int> active-tab-index: 0;
    property <bool> f4se-tab-activation-observed: false;
    in-out property <string> tools-last-action-error: "";
    in-out property <string> tools-disabled-utility-status: "Archive Patcher is deferred until S10.";
    in-out property <string> about-last-action-error: "";
    in-out property <string> about-nexus-copy-label: "Copy Link";
    in-out property <bool> about-nexus-copy-enabled: true;
    in-out property <string> about-discord-copy-label: "Copy Invite";
    in-out property <bool> about-discord-copy-enabled: true;
    in-out property <string> about-github-copy-label: "Copy Link";
    in-out property <bool> about-github-copy-enabled: true;
    callback update-source-selected(string);
    callback log-level-selected(string);
    callback overview-refresh-requested();
    callback overview-open-game-path-requested();
    callback overview-open-nexus-update-requested();
    callback overview-open-github-update-requested();
    callback overview-open-downgrade-manager-requested();
    callback overview-open-archive-patcher-requested();
    callback f4se-tab-activated();
    callback scanner-category-toggled(string, bool);
    callback scanner-scan-requested();
    callback scanner-result-selected(int);
    callback scanner-auto-fix-requested();
    callback scanner-copy-details-requested();
    callback scanner-file-list-requested();
    callback scanner-open-path-requested();
    callback scanner-open-url-requested();
    callback scanner-copy-url-requested();
    callback tool-action-requested(string);
    callback tools-open-downgrade-manager-requested();
    callback about-open-requested(string);
    callback about-copy-requested(string);
    callback about-copy-label-reset-requested(string);

    title: "Collective Modding Toolkit";
    width: 900px;
    height: 640px;

    // The tab labels and order mirror CMT/src/cm_checker.py and CMT/src/enums.py.
    f4se-tab-lazy-activation := Timer {
        interval: 16ms;
        running: root.active-tab-index == 1 && !root.f4se-tab-activation-observed;
        triggered => {
            root.f4se-tab-activation-observed = true;
            root.f4se-tab-activated();
        }
    }

    TabWidget {
        current-index <=> root.active-tab-index;
        Tab {
            title: "Overview";
            OverviewTab {
                overview-refresh-message <=> root.overview-refresh-message;
                overview-refresh-busy <=> root.overview-refresh-busy;
                overview-top-rows <=> root.overview-top-rows;
                overview-binary-rows <=> root.overview-binary-rows;
                overview-archive-rows <=> root.overview-archive-rows;
                overview-module-rows <=> root.overview-module-rows;
                overview-problems-summary <=> root.overview-problems-summary;
                overview-problem-rows <=> root.overview-problem-rows;
                overview-update-heading <=> root.overview-update-heading;
                overview-nexus-update-label <=> root.overview-nexus-update-label;
                overview-nexus-update-enabled <=> root.overview-nexus-update-enabled;
                overview-github-update-label <=> root.overview-github-update-label;
                overview-github-update-enabled <=> root.overview-github-update-enabled;
                overview-game-path-enabled <=> root.overview-game-path-enabled;
                overview-downgrade-label <=> root.overview-downgrade-label;
                overview-downgrade-enabled <=> root.overview-downgrade-enabled;
                overview-downgrade-status <=> root.overview-downgrade-status;
                overview-archive-patcher-label <=> root.overview-archive-patcher-label;
                overview-archive-patcher-enabled <=> root.overview-archive-patcher-enabled;
                overview-archive-patcher-status <=> root.overview-archive-patcher-status;
                overview-last-action-error <=> root.overview-last-action-error;
                refresh-requested => {
                    root.overview-refresh-requested();
                }
                open-game-path-requested => {
                    root.overview-open-game-path-requested();
                }
                open-nexus-update-requested => {
                    root.overview-open-nexus-update-requested();
                }
                open-github-update-requested => {
                    root.overview-open-github-update-requested();
                }
                open-downgrade-manager-requested => {
                    root.overview-open-downgrade-manager-requested();
                }
                open-archive-patcher-requested => {
                    root.overview-open-archive-patcher-requested();
                }
            }
        }

        Tab {
            title: "F4SE";
            F4seTab {
                f4se-status-text <=> root.f4se-status-text;
                f4se-busy <=> root.f4se-busy;
                f4se-loading-or-error-text <=> root.f4se-loading-or-error-text;
                f4se-unknown-game-detail <=> root.f4se-unknown-game-detail;
                f4se-rows <=> root.f4se-rows;
            }
        }

        Tab {
            title: "Scanner";
            ScannerTab {
                scanner-overview-issues-enabled <=> root.scanner-overview-issues-enabled;
                scanner-errors-enabled <=> root.scanner-errors-enabled;
                scanner-wrong-file-formats-enabled <=> root.scanner-wrong-file-formats-enabled;
                scanner-loose-previs-enabled <=> root.scanner-loose-previs-enabled;
                scanner-junk-files-enabled <=> root.scanner-junk-files-enabled;
                scanner-problem-overrides-enabled <=> root.scanner-problem-overrides-enabled;
                scanner-race-subgraphs-enabled <=> root.scanner-race-subgraphs-enabled;
                scanner-settings-read-only <=> root.scanner-settings-read-only;
                scanner-scan-button-text <=> root.scanner-scan-button-text;
                scanner-scan-button-enabled <=> root.scanner-scan-button-enabled;
                scanner-busy <=> root.scanner-busy;
                scanner-status-text <=> root.scanner-status-text;
                scanner-progress-text <=> root.scanner-progress-text;
                scanner-progress-percent <=> root.scanner-progress-percent;
                scanner-result-count-text <=> root.scanner-result-count-text;
                scanner-result-rows <=> root.scanner-result-rows;
                scanner-show-mod-column <=> root.scanner-show-mod-column;
                scanner-detail-visible <=> root.scanner-detail-visible;
                scanner-detail-mod <=> root.scanner-detail-mod;
                scanner-detail-problem <=> root.scanner-detail-problem;
                scanner-detail-summary <=> root.scanner-detail-summary;
                scanner-detail-solution <=> root.scanner-detail-solution;
                scanner-action-feedback <=> root.scanner-action-feedback;
                scanner-open-path-enabled <=> root.scanner-open-path-enabled;
                scanner-open-url-enabled <=> root.scanner-open-url-enabled;
                scanner-copy-url-enabled <=> root.scanner-copy-url-enabled;
                scanner-file-list-enabled <=> root.scanner-file-list-enabled;
                scanner-file-list-visible <=> root.scanner-file-list-visible;
                scanner-file-list-title <=> root.scanner-file-list-title;
                scanner-file-list-description <=> root.scanner-file-list-description;
                scanner-file-list-first-column <=> root.scanner-file-list-first-column;
                scanner-file-list-second-column <=> root.scanner-file-list-second-column;
                scanner-file-list-rows <=> root.scanner-file-list-rows;
                scanner-auto-fix-button-visible <=> root.scanner-auto-fix-button-visible;
                scanner-auto-fix-button-label <=> root.scanner-auto-fix-button-label;
                scanner-auto-fix-button-enabled <=> root.scanner-auto-fix-button-enabled;
                scanner-auto-fix-status-text <=> root.scanner-auto-fix-status-text;
                scanner-auto-fix-results-visible <=> root.scanner-auto-fix-results-visible;
                scanner-auto-fix-results-title <=> root.scanner-auto-fix-results-title;
                scanner-auto-fix-results-summary <=> root.scanner-auto-fix-results-summary;
                scanner-auto-fix-results-details <=> root.scanner-auto-fix-results-details;
                category-toggled(id, enabled) => {
                    root.scanner-category-toggled(id, enabled);
                }
                scan-requested => {
                    root.scanner-scan-requested();
                }
                result-selected(index) => {
                    root.scanner-result-selected(index);
                }
                auto-fix-requested => {
                    root.scanner-auto-fix-requested();
                }
                copy-details-requested => {
                    root.scanner-copy-details-requested();
                }
                file-list-requested => {
                    root.scanner-file-list-requested();
                }
                open-path-requested => {
                    root.scanner-open-path-requested();
                }
                open-url-requested => {
                    root.scanner-open-url-requested();
                }
                copy-url-requested => {
                    root.scanner-copy-url-requested();
                }
            }
        }

        Tab {
            title: "Tools";
            ToolsTab {
                tools-last-action-error <=> root.tools-last-action-error;
                tools-disabled-utility-status <=> root.tools-disabled-utility-status;
                tool-action-requested(action_id) => {
                    root.tool-action-requested(action_id);
                }
                open-downgrade-manager-requested => {
                    root.tools-open-downgrade-manager-requested();
                }
            }
        }

        Tab {
            title: "Settings";
            SettingsTab {
                update-source <=> root.update-source;
                log-level <=> root.log-level;
                update-source-selected(value) => {
                    root.update-source-selected(value);
                }
                log-level-selected(value) => {
                    root.log-level-selected(value);
                }
            }
        }

        Tab {
            title: "About";
            AboutTab {
                about-last-action-error <=> root.about-last-action-error;
                about-nexus-copy-label <=> root.about-nexus-copy-label;
                about-nexus-copy-enabled <=> root.about-nexus-copy-enabled;
                about-discord-copy-label <=> root.about-discord-copy-label;
                about-discord-copy-enabled <=> root.about-discord-copy-enabled;
                about-github-copy-label <=> root.about-github-copy-label;
                about-github-copy-enabled <=> root.about-github-copy-enabled;
                about-open-requested(action_id) => {
                    root.about-open-requested(action_id);
                }
                about-copy-requested(action_id) => {
                    root.about-copy-requested(action_id);
                }
                about-copy-label-reset-requested(action_id) => {
                    root.about-copy-label-reset-requested(action_id);
                }
            }
        }
    }
}

import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct OverviewUiRow {
    label: string,
    value: string,
    detail: string,
