import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct DowngraderStatusUiRow {
    display-name: string,
    status: string,
    severity: string,
    detail: string,
}

export struct DowngraderPlanUiRow {
    display-name: string,
    action: string,
    detail: string,
    severity: string,
}

export struct DowngraderLogUiRow {
    level: string,
    message: string,
}

component DowngraderStatusText inherits Text {
    in property <string> severity: "unknown";

    color: root.severity == "old-gen" ? #1e90ff :
        root.severity == "next-gen" ? #ab82ff :
        root.severity == "anniversary" ? #fa8072 :
        root.severity == "good" ? #8fdc8f :
        root.severity == "warning" ? #ffd166 :
        root.severity == "error" ? #ff7b7b :
        root.severity == "neutral" ? #a8a8a8 :
        #d8d8d8;
}

component DowngraderOptionRadio inherits Rectangle {
